// src/AdminDashboard.js
import React from 'react';
import { Link, Outlet } from 'react-router-dom';
import './adminDashboard.css'; // Create this CSS file for styling

const AdminDashboard = () => {
  return (
    <div className="admin-dashboard">
      <nav className="navbar">
        <h1>Admin Dashboard</h1>
        <div className="nav-container">
          <div className="nav-box"><Link to="add-officer">Add Officers</Link></div>
          <div className="nav-box"><Link to="manage-officers">Manage Officers</Link></div>
          <div className="nav-box"><Link to="add-project">Add Projects</Link></div>
          <div className="nav-box"><Link to="manage-projects">Manage Projects</Link></div>
          </div>
      </nav>
      <main className="dashboard-content">
        <Outlet /> {/* This will render the child routes */}
      </main>
    </div>  
  );
};

export default AdminDashboard;
